-- Add B1 Grammar Lessons
-- This migration adds 32 B1-level grammar lessons to the grammar_chapters table.
-- The lessons cover intermediate grammar topics including present perfect vs past simple,
-- narrative tenses, passive voice, modals, conditionals, relative clauses, and more.
--
-- IDEMPOTENCY: This migration uses WHERE NOT EXISTS to check for existing chapter_codes
-- before insertion, allowing safe re-execution without creating duplicates.

INSERT INTO public.grammar_chapters (chapter_code, title, cefr_level, form_content, meaning_content, use_content, contrast_notes, common_errors, diagnostic_hook, task_upgrades, micro_practice, cross_links, is_published, sort_order)
SELECT * FROM (VALUES
  ('B1.G.01', 'Present Perfect vs Past Simple', 'B1', 'Present Perfect: Subject + have/has + V3. Past Simple: Subject + V2 + time marker', 'Past Simple: finished time. Present Perfect: unfinished time or relevant result', 'Choose Past Simple for "when exactly?" Choose Present Perfect for experience or result', 'My grandfather went to Mexico (deceased). I have been to Mexico (alive, might go again)', 'Error: I have visited London last year. Fix: I visited London last year', 'Explain problems affecting you now. Share life experiences in interviews', 'Starter: I didn''t see him today → Upgrade: I haven''t seen him around today', '[{"type":"multiple_choice","prompt":"I ___ my keys yesterday","options":["have lost","lost"],"answer":"lost"}]'::jsonb, '[{"type":"prerequisite","chapter_code":"A2.G.01"},{"type":"advanced","chapter_code":"B1.G.02"}]'::jsonb, true, 1),
  ('B1.G.02', 'Present Perfect Continuous', 'B1', 'Subject + have/has + been + V-ing', 'Emphasizes duration and continuous nature of activity', 'Use with for/since to show how long. Focus on visible evidence', 'I have painted (result done). I have been painting (activity ongoing)', 'Error: I have been knowing him. Fix: I have known him (state verbs)', 'Explain why you look tired or stressed. Talk about duration', 'Starter: I work on this project recently → Upgrade: I''ve been spending time on this lately', '[{"type":"fill_blank","prompt":"Your eyes are red. Have you been ___?","answer":"crying"}]'::jsonb, '[{"type":"prerequisite","chapter_code":"B1.G.01"},{"type":"advanced","chapter_code":"B1.G.03"}]'::jsonb, true, 2),
  ('B1.G.03', 'Narrative Tenses', 'B1', 'Background: Past Continuous. Main events: Past Simple. Backstory: Past Perfect', 'Narrative tenses act like a camera showing background, action, and flashback', 'Setting: was shining. Action: ran. Flashback: had seen', 'When I arrived, they ate (together). When I arrived, they were eating (interrupted)', 'Error: I was waking up, then I was taking a shower. Fix: Use simple past for main events', 'Tell engaging stories. Write incident reports. Set the scene', 'Starter: I drove. I saw accident → Upgrade: While I was driving, I saw an accident', '[{"type":"multiple_choice","prompt":"I ___ home when I ___ $20","options":["was walking / found"],"answer":"was walking / found"}]'::jsonb, '[{"type":"prerequisite","chapter_code":"A2.G.01"},{"type":"advanced","chapter_code":"B1.G.04"}]'::jsonb, true, 3),
  ('B1.G.04', 'Past Perfect', 'B1', 'Subject + had + V3', 'Past of the past. Shows which action happened first', 'Use when narrating in simple past, referring to earlier event', 'We arrived, movie started (on time). We arrived, movie had started (late)', 'Error: I had lived in Brazil in 2010. Fix: Use only for two past events', 'Clarify timeline. Give excuses. Express regrets', 'Starter: I didn''t eat because I ate before → Upgrade: I wasn''t hungry because I had already eaten', '[{"type":"fill_blank","prompt":"I couldn''t buy coffee because I ___ my wallet","answer":"had forgotten"}]'::jsonb, '[{"type":"prerequisite","chapter_code":"B1.G.03"},{"type":"advanced","chapter_code":"B2.G.02"}]'::jsonb, true, 4),
  ('B1.G.05', 'Future Continuous / Future Perfect', 'B1', 'Future Continuous: will be + V-ing. Future Perfect: will have + V3', 'Future Continuous: action in progress at future moment. Future Perfect: completed by future time', 'Use to soften questions. Use by for deadlines', 'I will call at 8 (dial at 8). I will be calling at 8 (in middle of call)', 'Error: I will have finish. Fix: will have + V3', 'Understand deadlines. Project into future. Ask about plans', 'Starter: I will finish before Friday → Upgrade: I will have this wrapped up by Friday', '[{"type":"multiple_choice","prompt":"By next year, she will have ___","options":["graduated"],"answer":"graduated"}]'::jsonb, '[{"type":"prerequisite","chapter_code":"A2.G.05"},{"type":"advanced","chapter_code":"B1.G.07"}]'::jsonb, true, 5),
  ('B1.G.06', 'Reported Speech', 'B1', 'Backshift tenses. Statements: said that. Questions: asked if/where', 'Creates distance. Processing information from earlier time', 'That is optional. Say vs Tell: Tell + person', 'Say: He said that. Tell: He told me that', 'Error: He said me that. Fix: He said that OR He told me that', 'Pass on messages. Gossip. Summarize meetings', 'Starter: He said I will be late → Upgrade: He mentioned that he''d be late', '[{"type":"multiple_choice","prompt":"She ___ me that she was moving","options":["told"],"answer":"told"}]'::jsonb, '[{"type":"prerequisite","chapter_code":"A2.G.16"},{"type":"advanced","chapter_code":"B1.G.16"}]'::jsonb, true, 6),
  ('B1.G.07', 'Passive Voice (Expanded)', 'B1', 'Subject + be (tense) + V3. Add agent with by', 'Flips focus from doer to receiver', 'Unknown doer. Obvious doer. Diplomatic reporting', 'Active: Dog bit John. Passive: John was bitten by dog', 'Error: House built in 1990. Fix: House was built in 1990', 'Describe processes. Write formal reports. Report tactfully', 'Starter: Someone broke printer → Upgrade: The printer got broken', '[{"type":"transformation","prompt":"Rewrite passive: Someone cleans office","answer":"Office is cleaned"}]'::jsonb, '[{"type":"prerequisite","chapter_code":"A2.G.15"},{"type":"advanced","chapter_code":"B2.G.05"}]'::jsonb, true, 7),
  ('B1.G.08', 'Modals of Deduction (Present)', 'B1', 'Must be (99% true). Might/could be (50%). Can''t be (99% false)', 'Express confidence in conclusions drawn from evidence', 'Must: strong evidence for yes. Can''t: strong evidence for no. Might: 50/50', 'Deduction: She must be boss. Fact: She is boss', 'Error: He mustn''t be home. Fix: He can''t be home (for deduction)', 'Make educated guesses. Draw conclusions. Express certainty', 'Starter: I think he is sick → Upgrade: He must be coming down with something', '[{"type":"multiple_choice","prompt":"You''ve traveled 14 hours. You ___ be exhausted","options":["must"],"answer":"must"}]'::jsonb, '[{"type":"prerequisite","chapter_code":"A2.G.06"},{"type":"advanced","chapter_code":"B2.G.03"}]'::jsonb, true, 8),
  ('B1.G.09', 'Modals of Advice and Obligation', 'B1', 'Should/ought to: general advice. Had better: urgent warning', 'Should: good idea. Ought to: formal/moral duty. Had better: threat attached', 'Had better for immediate situations. Should for general advice', 'Should: friendly recommendation. Had better: warning with consequence', 'Error: You ought listen. Fix: ought to. Error: had better to leave. Fix: had better leave', 'Give urgent advice. Express obligations. Warn about consequences', 'Starter: It is good idea to leave → Upgrade: We''d better head out before traffic gets bad', '[{"type":"multiple_choice","prompt":"It''s raining. You ___ take umbrella","options":["had better"],"answer":"had better"}]'::jsonb, '[{"type":"prerequisite","chapter_code":"A1.G.17"},{"type":"advanced","chapter_code":"B1.G.29"}]'::jsonb, true, 9),
  ('B1.G.10', 'Conditionals 1 and 2 (Productive Control)', 'B1', '1st: If + present, will + base. 2nd: If + past, would + base', '1st: real, realistic chance. 2nd: impossible, unlikely, fantasy', '1st: warnings, threats, realistic planning. 2nd: If I were you advice', 'Real: If I win, I will lower taxes. Unreal: If I won, I would lower taxes', 'Error: If I will see him. Fix: If acts as wall. Will goes in result', 'Negotiate terms. Make plans. Hypothesize about realities', 'Starter: If you buy, I give discount → Upgrade: If you''re willing to sign, we can offer 10%', '[{"type":"multiple_choice","prompt":"If I ___ your wallet, I will call","options":["find"],"answer":"find"}]'::jsonb, '[{"type":"prerequisite","chapter_code":"A2.G.07"},{"type":"advanced","chapter_code":"B1.G.11"}]'::jsonb, true, 10),
  ('B1.G.11', 'Conditionals: Unless / As Long As / Provided That', 'B1', 'Unless = if not. As long as = on condition that. Provided that = formal condition', 'Set strict boundaries and conditions', 'Unless for negative condition. As long as/provided that for formal terms', 'Unless you call, I won''t know. If you don''t call, I won''t know', 'Error: Unless you don''t come. Fix: Unless already means if not', 'Set boundaries. Agree to terms. Sound professional', 'Starter: You can''t come unless invited → Upgrade: Entry restricted unless valid ticket', '[{"type":"transformation","prompt":"Rewrite using unless: If you don''t study, you fail","answer":"Unless you study, you fail"}]'::jsonb, '[{"type":"prerequisite","chapter_code":"B1.G.10"},{"type":"advanced","chapter_code":"B2.G.07"}]'::jsonb, true, 11),
  ('B1.G.12', 'Gerunds/Infinitives (Expanded Verb Sets)', 'B1', 'Gerund verbs: enjoy, avoid, finish, mind, suggest, practice, consider. Infinitive verbs: want, need, plan, decide, hope, promise, attempt', 'Expand repertoire of verbs taking gerunds or infinitives', 'Gerunds: experiences, habits. Infinitives: future plans, intentions', 'Stop smoking (quit habit). Stop to smoke (pause to smoke)', 'Error: I enjoy to cook. Fix: I enjoy cooking', 'Talk about adopting habits. Discuss plans. Explain preferences', 'Starter: I want to stop smoking → Upgrade: I''m determined to quit smoking once and for all', '[{"type":"fill_blank","prompt":"She is ___ moving to new city","answer":"considering"}]'::jsonb, '[{"type":"prerequisite","chapter_code":"A2.G.09"},{"type":"advanced","chapter_code":"B2.G.12"}]'::jsonb, true, 12),
  ('B1.G.13', 'Relative Clauses (Defining vs Non-Defining)', 'B1', 'Defining (no commas): who/that/which. Non-defining (commas): who/which', 'Defining: essential info to identify. Non-defining: extra info', 'Defining: necessary to understand. Non-defining: interesting details', 'Student who scored highest won prize (defining). My sister, who scored highest, won prize (non-defining)', 'Error: Person, who called, was boss. Fix: No commas in defining', 'Add details without new sentence. Provide background. Make writing sophisticated', 'Starter: Person called me. He was boss → Upgrade: Person who called me was boss', '[{"type":"transformation","prompt":"Combine: Book is interesting. I read it","answer":"Book that I read is interesting"}]'::jsonb, '[{"type":"prerequisite","chapter_code":"A2.G.15"},{"type":"advanced","chapter_code":"B1.G.15"}]'::jsonb, true, 13),
  ('B1.G.14', 'Linking and Discourse Markers (B1 Set)', 'B1', 'Contrast: however, nevertheless. Addition: furthermore, moreover. Cause/Effect: therefore, consequently. Sequence: first, then, next', 'Show relationships between ideas. Organize thoughts', 'Contrast: show opposing ideas. Addition: add points. Cause/Effect: show logic. Sequence: organize events', 'But informal, middle of sentence. However formal, starts sentence', 'Error: I went, however, to store. Fix: Place at beginning or clause', 'Organize presentations. Show relationships. Sound professional', 'Starter: I like coffee. I don''t like tea → Upgrade: I like coffee. However, I don''t like tea', '[{"type":"fill_blank","prompt":"I wanted to go. ___, I had to work","answer":"However"}]'::jsonb, '[{"type":"prerequisite","chapter_code":"A2.G.16"},{"type":"advanced","chapter_code":"B1.G.15"}]'::jsonb, true, 14),
  ('B1.G.15', 'Clause Combining: Because/So/Although/While', 'B1', 'Because: cause. So: result. Although: concession. While: contrast/time', 'Show relationships between clauses', 'Because: explain why. So: show result. Although: show contrast. While: show simultaneity', 'Because shows cause. So shows result. Although more formal than but', 'Error: Because it rained so I stayed home. Fix: Use either because OR so', 'Show contrast. Explain cause/effect. Combine ideas smoothly', 'Starter: It rained. I went out anyway → Upgrade: Although it rained, I went out', '[{"type":"transformation","prompt":"Combine using because: I stayed home. It rained","answer":"I stayed home because it rained"}]'::jsonb, '[{"type":"prerequisite","chapter_code":"B1.G.14"},{"type":"advanced","chapter_code":"B2.G.10"}]'::jsonb, true, 15),
  ('B1.G.16', 'Indirect Questions', 'B1', 'Direct: Where is station? Indirect: Can you tell me where the station is?', 'More polite and formal than direct questions', 'Use in professional emails. Ask respectfully', 'Direct: Where is bathroom? Indirect: Could you tell me where bathroom is?', 'Error: Where is the station? Fix: Where the station is (normal word order)', 'Be polite with strangers. Ask professionally. Sound courteous', 'Starter: Where is bathroom? → Upgrade: Could you tell me where bathroom is?', '[{"type":"transformation","prompt":"Change to indirect: Where is station?","answer":"Can you tell me where the station is?"}]'::jsonb, '[{"type":"prerequisite","chapter_code":"B1.G.06"},{"type":"advanced","chapter_code":"B2.G.15"}]'::jsonb, true, 16),
  ('B1.G.17', 'Question Tags & Short Responses', 'B1', 'Positive + negative tag: You''re coming, aren''t you? Short: Yes, I am', 'Confirm information. Invite agreement', 'Keep conversations flowing. Include listener. Confirm politely', 'Real question: Are you coming? Tag: You''re coming, aren''t you?', 'Error: You''re coming, don''t you? Fix: Match auxiliary: aren''t you?', 'Keep conversation flowing. Confirm information. Sound natural', 'Starter: You''re coming to party → Upgrade: You''re coming to party, aren''t you?', '[{"type":"fill_blank","prompt":"You''re coming, ___ you?","answer":"aren''t"}]'::jsonb, '[{"type":"prerequisite","chapter_code":"A2.G.17"},{"type":"advanced","chapter_code":"B2.G.18"}]'::jsonb, true, 17),
  ('B1.G.18', 'Comparatives for Persuasion', 'B1', 'Comparative + than. Intensifiers: much, far, a lot, significantly', 'Highlight differences to persuade', 'Use in sales pitches. Persuade people. Emphasize advantages', 'Comparative: faster than. Superlative: fastest', 'Error: more faster. Fix: Use either -er OR more', 'Pitch products. Persuade people. Make compelling arguments', 'Starter: This product is good → Upgrade: This product is significantly more reliable than competitors', '[{"type":"fill_blank","prompt":"This laptop is ___ than that one","answer":"faster"}]'::jsonb, '[{"type":"prerequisite","chapter_code":"A1.G.20"},{"type":"advanced","chapter_code":"B2.G.20"}]'::jsonb, true, 18),
  ('B1.G.19', 'Determiners: All/Most/Both/Each/Every', 'B1', 'All: 100%. Most: >50%. Both: two. Each: individual. Every: all + rule', 'Generalize about groups. Express inclusion degrees', 'All: 100%. Most: more than half. Both: two things. Each: individual. Every: rule', 'All students passed. Every student must pass', 'Error: Each students. Fix: Each student (singular)', 'Generalize about groups. Make statements about rules. Describe items', 'Starter: All people like pizza → Upgrade: Most people enjoy pizza, but not everyone', '[{"type":"fill_blank","prompt":"___ students passed exam","answer":"All"}]'::jsonb, '[{"type":"prerequisite","chapter_code":"A2.G.11"},{"type":"advanced","chapter_code":"B2.G.19"}]'::jsonb, true, 19),
  ('B1.G.20', 'Pronoun Reference for Cohesion', 'B1', 'Personal: he, she, it, they. Possessive: his, her, its, their. Demonstrative: this, that', 'Create cohesion. Avoid repetition. Connect sentences', 'Use pronouns to connect smoothly. Avoid repeating nouns', 'Clear: I met Sarah. She was happy. Unclear: I met Sarah and mother. She was happy', 'Error: Unclear reference. Fix: Make pronoun clearly refer to one noun', 'Write smooth paragraphs. Create professional writing. Make writing flow', 'Starter: I met John. John was happy → Upgrade: I met John. He was happy', '[{"type":"fill_blank","prompt":"I met Sarah. ___ was happy","answer":"She"}]'::jsonb, '[{"type":"prerequisite","chapter_code":"A1.G.02"},{"type":"advanced","chapter_code":"B2.G.21"}]'::jsonb, true, 20),
  ('B1.G.21', 'Articles III', 'B1', 'The: specific, known. A/An: general, unknown. Zero: general plural/uncountable', 'Master complex article rules', 'The: unique things, superlatives, ordinals. Zero: general concepts', 'The sun (unique). Sunshine (general). The best (superlative)', 'Error: The life is beautiful. Fix: Life is beautiful', 'Make philosophical statements. Discuss unique things. Sound educated', 'Starter: I think life is beautiful → Upgrade: Life is one of most precious gifts', '[{"type":"fill_blank","prompt":"___ sun is largest star","answer":"The"}]'::jsonb, '[{"type":"prerequisite","chapter_code":"A2.G.10"},{"type":"advanced","chapter_code":"B2.G.22"}]'::jsonb, true, 21),
  ('B1.G.22', 'Preposition Patterns (Expanded)', 'B1', 'Verb + prep: look for, depend on. Adj + prep: interested in. Noun + prep: reason for', 'Fixed combinations that must be memorized', 'Learn as chunks. Use without translating. Practice regularly', 'Look for (search). Look at (observe). Interested in (not on)', 'Error: Looking at my keys. Fix: Looking for my keys', 'Use verbs correctly. Sound natural. Avoid common mistakes', 'Starter: I look for keys → Upgrade: I''ve been looking for keys all morning', '[{"type":"fill_blank","prompt":"I''m looking ___ my keys","answer":"for"}]'::jsonb, '[{"type":"prerequisite","chapter_code":"A2.G.21"},{"type":"advanced","chapter_code":"B2.G.23"}]'::jsonb, true, 22),
  ('B1.G.23', 'Phrasal Verbs (Systematic)', 'B1', 'Separable: put on, take off. Inseparable: look after, deal with', 'Combinations creating new meanings', 'Learn as chunks. Understand separable vs inseparable', 'Put on coat / Put coat on. Look after sister (NOT: look sister after)', 'Error: Look sister after. Fix: Look after sister (inseparable)', 'Understand native speakers. Sound natural. Use correctly', 'Starter: I removed coat → Upgrade: I took off my coat', '[{"type":"fill_blank","prompt":"I ___ my coat","answer":"put on / put my coat on"}]'::jsonb, '[{"type":"prerequisite","chapter_code":"A2.G.22"},{"type":"advanced","chapter_code":"B2.G.24"}]'::jsonb, true, 23),
  ('B1.G.24', 'Adjective Order (Basic)', 'B1', 'Opinion, Size, Age, Color, Origin, Material, Purpose', 'Standard order makes English sound natural', 'Follow standard order. Use 2-3 adjectives max', 'Beautiful old table (correct). Old beautiful table (unnatural)', 'Error: Red beautiful table. Fix: Beautiful red table', 'Describe items clearly. Sound natural. Use multiple adjectives', 'Starter: Bag is red, leather → Upgrade: Beautiful red leather bag', '[{"type":"fill_blank","prompt":"I have ___ ___ table","answer":"beautiful wooden"}]'::jsonb, '[{"type":"prerequisite","chapter_code":"A1.G.19"},{"type":"advanced","chapter_code":"B2.G.25"}]'::jsonb, true, 24),
  ('B1.G.25', '"So/Such" for Emphasis', 'B1', 'So + adj/adv. Such + adj + noun', 'Express strong emotions and emphasis', 'So: emphasize adjective. Such: emphasize noun phrase', 'So: Food was so delicious. Such: It was such delicious food', 'Error: So delicious food. Fix: Such delicious food', 'Express strong emotions. Emphasize feelings. Sound expressive', 'Starter: Movie was good → Upgrade: Movie was so good!', '[{"type":"fill_blank","prompt":"Food was ___ delicious","answer":"so"}]'::jsonb, '[{"type":"prerequisite","chapter_code":"A2.G.25"},{"type":"advanced","chapter_code":"B2.G.26"}]'::jsonb, true, 25),
  ('B1.G.26', '"Too/Enough" (Productive)', 'B1', 'Too + adj (more than necessary). Adj + enough (sufficient)', 'Express whether something is sufficient or excessive', 'Too: more than necessary. Enough: sufficient', 'Too: negative. Enough: neutral/positive', 'Error: Enough hot. Fix: Hot enough', 'Explain constraints. Describe limitations. Express why impossible', 'Starter: Project difficult, no time → Upgrade: Project too difficult, not enough time', '[{"type":"fill_blank","prompt":"Coffee is ___ hot to drink","answer":"too"}]'::jsonb, '[{"type":"prerequisite","chapter_code":"A2.G.25"},{"type":"advanced","chapter_code":"B2.G.27"}]'::jsonb, true, 26),
  ('B1.G.27', 'Basic Noun Clauses', 'B1', 'Noun clauses as subjects/objects. That-clauses, Wh-clauses, If/Whether clauses', 'Function as nouns in sentences', 'Express complex ideas. Report thoughts. Express uncertainty', 'Noun clause: I know what you mean. Adj clause: Person who called', 'Error: What do you mean? Fix: What you mean (statement order)', 'State opinions. Express complex ideas. Report thoughts', 'Starter: You are right. I believe → Upgrade: I believe that you''re right', '[{"type":"transformation","prompt":"Combine: You are right. I believe","answer":"I believe that you''re right"}]'::jsonb, '[{"type":"prerequisite","chapter_code":"B1.G.13"},{"type":"advanced","chapter_code":"B2.G.28"}]'::jsonb, true, 27),
  ('B1.G.28', '"The More…, The More…" (Intro)', 'B1', 'The + comparative, the + comparative', 'Show cause and effect relationships', 'Explain cause/effect. Show connections. Make arguments', 'More you study, better you''ll do (shows relationship)', 'Error: More you study, you''ll do better. Fix: The more...the more', 'Explain relationships. Show connections. Make arguments', 'Starter: Practice more, improve → Upgrade: More you practice, more you''ll improve', '[{"type":"fill_blank","prompt":"The ___ you study, the ___ you''ll do","answer":"more / better"}]'::jsonb, '[{"type":"prerequisite","chapter_code":"B1.G.18"},{"type":"advanced","chapter_code":"B2.G.29"}]'::jsonb, true, 28),
  ('B1.G.29', '"Be Supposed To" (Expectations)', 'B1', 'Present: supposed to be. Past: was supposed to', 'Express expectations, rules, what people think you should do', 'Talk about rules. Explain what you were supposed to do', 'Be supposed to: external expectation. Should: advice', 'Error: I supposed to go. Fix: I''m supposed to go', 'Talk about rules. Explain expectations. Discuss obligations', 'Starter: Rule is no eating → Upgrade: You''re not supposed to eat here', '[{"type":"fill_blank","prompt":"You ___ supposed to be here at 9","answer":"are"}]'::jsonb, '[{"type":"prerequisite","chapter_code":"B1.G.09"},{"type":"advanced","chapter_code":"B2.G.30"}]'::jsonb, true, 29),
  ('B1.G.30', 'Participles as Adjectives (Bored/Boring)', 'B1', '-ed: how you feel. -ing: quality of thing', 'Participles function as adjectives', 'Use -ed for feelings. Use -ing for qualities', 'Bored: I feel. Boring: movie causes boredom', 'Error: I''m boring. Fix: I''m bored', 'Describe emotions. Express reactions. Describe qualities', 'Starter: Don''t like class, not interesting → Upgrade: Not interested, class is boring', '[{"type":"fill_blank","prompt":"I''m ___ with movie","answer":"bored"}]'::jsonb, '[{"type":"prerequisite","chapter_code":"A1.G.09"},{"type":"advanced","chapter_code":"B2.G.31"}]'::jsonb, true, 30),
  ('B1.G.31', 'Basic Formal vs Informal Grammar Choices', 'B1', 'Formal: full forms, passive, complex sentences. Informal: contractions, active, simple', 'Different contexts require different formality levels', 'Formal: professional emails, presentations. Informal: casual conversations', 'Formal: I am unable. Informal: I can''t', 'Error: Informal in formal context. Fix: Use formal structures', 'Adjust tone based on audience. Sound professional. Sound natural', 'Starter: I can''t do it → Upgrade (formal): I am unable to do this', '[{"type":"multiple_choice","prompt":"___ we begin?","options":["Let''s","Shall"],"answer":"Shall"}]'::jsonb, '[{"type":"prerequisite","chapter_code":"A1.G.01"},{"type":"advanced","chapter_code":"B2.G.32"}]'::jsonb, true, 31),
  ('B1.G.32', 'Grammar for Email Basics', 'B1', 'Subject line, greeting, opening, body, closing, signature', 'Email is formal written medium requiring professional grammar', 'Use clear subject lines. Use formal greetings. Organize clearly', 'Email: formal, complete sentences. Text: informal, abbreviations', 'Error: Informal in professional email. Fix: Use formal structures', 'Write clear emails. Communicate professionally. Make good impressions', 'Starter: I need help → Upgrade: I would appreciate your assistance', '[{"type":"fill_blank","prompt":"I am writing to ___ you","answer":"inform"}]'::jsonb, '[{"type":"prerequisite","chapter_code":"B1.G.31"},{"type":"advanced","chapter_code":"B2.G.33"}]'::jsonb, true, 32)
) AS new_chapters(chapter_code, title, cefr_level, form_content, meaning_content, use_content, contrast_notes, common_errors, diagnostic_hook, task_upgrades, micro_practice, cross_links, is_published, sort_order)
WHERE NOT EXISTS (
  SELECT 1 FROM public.grammar_chapters 
  WHERE chapter_code = new_chapters.chapter_code
);
